function initStickySidebar() {
	const sidebar = document.querySelector('.content-section .sidebar-wrapper');
	const contentSection = document.querySelector('.content-section');

	if (!sidebar || !contentSection) return;

	// Get all anchor links and their corresponding sections
	const tocLinks = sidebar.querySelectorAll('.anchor-list a');
	const sections = [];

	// Collect all sections that have IDs matching the TOC links
	tocLinks.forEach(link => {
		const hash = link.getAttribute('href');
		if (hash && hash.startsWith('#')) {
			const sectionId = hash.substring(1);
			const section = document.getElementById(sectionId);
			if (section) {
				sections.push({
					link: link,
					section: section,
					id: sectionId
				});
			}
		}

import esbuild from 'esbuild';
import { glob } from 'glob';
import path from 'path';

async function build() {
  try {
    /**
     * ===============================
     * Build the main combined js
     * ===============================
     */
    // Build the main combined.js (trackQuizEvent only, for backward compatibility)
    await esbuild.build({
      bundle: true,
      minify: true,
      sourcemap: false,
      format: 'iife',
      entryPoints: ['src/static/js/index.js'],
      outfile: 'src/static/js/dist/combined.js',
    });
    console.log('✓ Built combined.js');

    /**
     * ===============================
     * Build the page bundles
     * ===============================
     */
    // Find all bundle entry points
    const bundleFiles = await glob('src/static/js/pages/*.bundle.js');

    // Build each page bundle
    for (const bundleFile of bundleFiles) {
      const filename = path.basename(bundleFile, '.bundle.js');
      await esbuild.build({
        bundle: true,
        minify: true,
        sourcemap: false,
        format: 'iife',
        entryPoints: [bundleFile],
        outfile: `src/static/js/dist/pages/${filename}.bundle.min.js`,
        external: ['jquery'],
      });
      console.log(`✓ Built ${filename}.bundle.min.js`);
    }

    console.log('\n🎉 All bundles built successfully!');
  } catch (err) {
    console.error('esbuild failed:', err);
    process.exit(1);
  }

